Note that above workarounds does not help when you have objects. For now, here is my solution:

```javascript
/**
 * Encodes a single query param
 */
function encodeAxiosParam(value) {
    let v = value;
    if (toString.call(value) === "[object Date]") {
      v = value.toISOString();
    } else if (typeof value === "object") {
      v = JSON.stringify(value);
    }
    return encodeURIComponent(v);
}

/**
 * Serializes params to a query string like axios pre-v1
 *
 * {
 *   object: { a: 1 },                        // object=%7B%22a%22:1%7D
 *   arrayOfArray: [[1, 2, ","], [2]],        // arrayOfArray[]=[1,2,%22,%22]&arrayOfArray[]=[2]
 *   arrayOfNullUndefined: [null, undefined], // arrayOfNullUndefined[]=null&arrayOfNullUndefined[]=undefined
 *   arrayOfObject: [{ id: 1 }, { id: 12 }],  // arrayOfObject[]=%7B%22id%22:1%7D&arrayOfObject[]=%7B%22id%22:12%7D
 *   arrayOfString: ["a", "b", "c"],          // arrayOfString[]=a&arrayOfString[]=b&arrayOfString[]=c
 *   undefinable: undefined,                  // X
 *   nullable: null,                          // X
 *   emptyArray: [],                          // X
 *   emptyString: "",                         // emptyString=
 *   emptyObject: {},                         // emptyObject=%7B%7D
 *   date: new Date("1970-01-01"),            // date=1970-01-01T00:00:00.000Z
 * }
 *
 * FIXME: Remove this in favor of updating the API endpoints
 */
function paramsSerializer(params) {
  return Object.entries(params)
    .filter(
      ([, value]) =>
        value !== undefined &&
        value !== null &&
        (Array.isArray(value) ? value.length > 0 : true)
    )
    .map(([key, value]) => {
      if (Array.isArray(value)) {
        return value.map((v) => `${key}[]=${encodeAxiosParam(v)}`).join('&')
      }
      return `${key}=${encodeAxiosParam(value)}`
    })
    .join('&')
}
```

It does differ during some serialization, which should not be impactful as those are mostly url-encoded changes:

| axios | custom |
| ------ | ------ |
| `object=%7B%22a%22:1%7D` | `object=%7B%22a%22%3A1%7D` |
| `arrayOfArray[]=[1,2,%22,%22]&arrayOfArray[]=[2]` | `arrayOfArray[]=%5B1%2C2%2C%22%2C%22%5D&arrayOfArray[]=%5B2%5D` |
| `arrayOfObject[]=%7B%22id%22:1%7D&arrayOfObject[]=%7B%22id%22:12%7D` | `arrayOfObject[]=%7B%22id%22%3A1%7D&arrayOfObject[]=%7B%22id%22%3A12%7D` |
| `date=1970-01-01T00:00:00.000Z` | `date=1970-01-01T00%3A00%3A00.000Z` |

To avoid these differences, we can use the `encode` function from `v0.21.4` in-place of the `encodeURIComponent` calls:

https://github.com/axios/axios/blob/a64050a6cfbcc708a55a7dc8030d85b1c78cdf38/lib/helpers/buildURL.js#L5-L13


For the one wanting a "bug-to-bug" compatible solutions inspired from [`v0.21.4`](https://github.com/axios/axios/blob/a64050a6cfbcc708a55a7dc8030d85b1c78cdf38/lib/helpers/buildURL.js)
<details>
  <summary>View `v0.21.4` code (self-contained)</summary>
  
  ```javascript
  'use strict';
  
  function encode(val) {
    return encodeURIComponent(val).
    replace(/%3A/gi, ':').
    replace(/%24/g, '$').
    replace(/%2C/gi, ',').
    replace(/%20/g, '+').
    replace(/%5B/gi, '[').
    replace(/%5D/gi, ']');
  }
  
  function utilsIsURLSearchParams(val) {
    return typeof URLSearchParams !== 'undefined' && val instanceof URLSearchParams;
  }
  
  function utilsIsArray(val) {
    return toString.call(val) === '[object Array]';
  }
  
  function utilsIsDate(val) {
    return toString.call(val) === '[object Date]';
  }
  
  function utilsIsObject(val) {
    return val !== null && typeof val === 'object';
  }
  
  function utilsForEach(obj, fn) {
    // Don't bother if no value provided
    if (obj === null || typeof obj === 'undefined') {
      return;
    }
  
    // Force an array if not already something iterable
    if (typeof obj !== 'object') {
      /*eslint no-param-reassign:0*/
      obj = [obj];
    }
  
    if (utilsIsArray(obj)) {
      // Iterate over array values
      for (var i = 0, l = obj.length; i < l; i++) {
        fn.call(null, obj[i], i, obj);
      }
    } else {
      // Iterate over object keys
      for (var key in obj) {
        if (Object.prototype.hasOwnProperty.call(obj, key)) {
          fn.call(null, obj[key], key, obj);
        }
      }
    }
  }
  
  /**
   * Build a queryString as Axios v0.21.4 would do
   *
   * @param {object} [params] The params to be appended
   * @returns {string} The serialized params
   */
  function paramsSerializer(params) {
    if (utilsIsURLSearchParams(params)) {
      return params.toString();
    }
  
    var parts = [];
  
    utilsForEach(params, function serialize(val, key) {
      if (val === null || typeof val === 'undefined') {
        return;
      }
  
      if (utilsIsArray(val)) {
        key = key + '[]';
      } else {
        val = [val];
      }
  
      utilsForEach(val, function parseValue(v) {
        if (utilsIsDate(v)) {
          v = v.toISOString();
        } else if (utilsIsObject(v)) {
          v = JSON.stringify(v);
        }
        parts.push(encode(key) + '=' + encode(v));
      });
    });
  
    return parts.join('&');
  };
  ```
  
