// Custom adapter to handle FormData
async function customAdapter(config) {
  if (config.data instanceof FormData) {
    // Generate a unique boundary
    const boundary = `--------------------------${Date.now().toString(16)}`;

    // Construct the multipart/form-data body
    const body = await formDataToBuffer(config.data, boundary);

    // Set the correct Content-Type header with the boundary
    config.headers['Content-Type'] = `multipart/form-data; boundary=${boundary}`;

    // Replace the data with the constructed body
    config.data = body;
  }

  // Use the default Axios adapter to send the request
  return axios.defaults.adapter(config);
}

// Helper function to convert FormData to a Buffer
function formDataToBuffer(formData, boundary) {
  return new Promise((resolve, reject) => {
    const chunks = [];

    // Create a readable stream from the FormData object
    const stream = formData.getBufferStream();
    stream.on('data', (chunk) => chunks.push(chunk));
    stream.on('end', () => resolve(Buffer.concat(chunks)));
    stream.on('error', (error) => reject(error));
  });
}

